[['mock] [--app ezybiz|callconcierge|both]\n# Default: both apps\n\nMOCK_ARG="', 'APPS_TO_RUN="both', 'Parse command line arguments\nwhile [[ $# -gt 0 ]]; do\n  case $1 in\n    --mock)\n      MOCK_ARG="--mock"\n      shift\n      ;;\n    --app)\n      APPS_TO_RUN="$2"\n      shift 2\n      ;;\n    --help|-h)\n      echo', 'Usage: ./run-all.sh [OPTIONS]"\n      echo "', 'echo "Options:"\n      echo "  --mock              Run in mock mode (no API charges)"\n      echo', 'app [ezybiz|callconcierge|both]   Specify which app(s) to run (default: both)"\n      echo "', 'echo "Examples:"\n      echo "  ./run-all.sh"\n      echo "  ./run-all.sh --mock"\n      echo "  ./run-all.sh --app ezybiz"\n      echo "  ./run-all.sh --app callconcierge --mock"\n      exit 0\n      ;;\n    *)\n      echo "Unknown option: $1"\n      echo "Use --help for usage information"\n      exit 1\n      ;;\n  esac\ndone\n\nSCRIPT_DIR="$(cd "$(dirname "$0")/ezybiz-repo/scripts" && pwd)"\n\nif [ "$MOCK_ARG" == "--mock'], ['$APPS_TO_RUN" == "ezybiz'], ['$APPS_TO_RUN" == "both'], ['$APPS_TO_RUN" == "callconcierge'], ['$APPS_TO_RUN" == "both']]